mapper.update:
BEGIN
	EXECUTE IMMEDIATE 'DROP SEQUENCE SEQ_PLACE_NO';
EXCEPTION
	WHEN OTHERS THEN
		IF SQLCODE != -2289 THEN
			RAISE;
		END IF;
END;

BEGIN
	EXECUTE IMMEDIATE 'CREATE SEQUENCE SEQ_PLACE_NO START WITH 1 INCREMENT BY 1';
END;

BEGIN
	EXECUTE IMMEDIATE 'DROP SEQUENCE SEQ_PLACE_TAG_MAP_NO';
EXCEPTION
	WHEN OTHERS THEN
		IF SQLCODE != -2289 THEN
			RAISE;
		END IF;
END;

BEGIN
	EXECUTE IMMEDIATE 'CREATE SEQUENCE SEQ_PLACE_TAG_MAP_NO START WITH 1 INCREMENT BY 1';
END;

BEGIN
	EXECUTE IMMEDIATE 'DROP SEQUENCE SEQ_HOURS_ID';
EXCEPTION
	WHEN OTHERS THEN
		IF SQLCODE != -2289 THEN
			RAISE;
		END IF;
END;

BEGIN
	EXECUTE IMMEDIATE 'CREATE SEQUENCE SEQ_HOURS_ID START WITH 1 INCREMENT BY 1';
END;

mapper.select:
SELECT ua.USER_NO
FROM USER_AUTHENTICATION ua
WHERE ua.USER_AUTH_ID = #{value}

mapper.insert:
INSERT INTO PLACE (
	PLACE_NO, PLACE_CONTENT_ID, PLACE_NAME, PLACE_CATEGORY, PLACE_ADDRESS,
	PLACE_LATITUDE, PLACE_LONGITUDE, PLACE_RATING,
	PLACE_NUMBER, PLACE_THUMBNAIL_URL
) VALUES (
	#{placeNo}, #{placeContentId}, #{placeName}, #{placeCategory}, #{placeAddress},
	#{placeLatitude}, #{placeLongitude}, 0,
	#{placeNumber}, #{placeThumbnailUrl}
)

INSERT INTO PLACE_TAG_MAP (
	PLACE_TAG_NO, PLACE_NO, TAG_CODE, TAG_WEIGHT, TAG_SOURCE, TAG_CONFIDENCE
) VALUES (
	SEQ_PLACE_TAG_MAP_NO.NEXTVAL, #{placeNo}, #{tagCode}, #{tagWeight}, #{tagSource}, #{tagConfidence}
)

INSERT INTO PLACE_HOURS (
	HOURS_ID, PLACE_NO, DAY_OF_WEEK, OPEN_TIME, CLOSE_TIME,
	BREAK_STRAT_TIME, BREAK_END_TIME, LAST_ORDER, IS_CLOSED
) VALUES (
	SEQ_HOURS_ID.NEXTVAL, #{placeNo}, #{dayOfWeek}, #{openTime}, #{closeTime},
	#{breakStratTime}, #{breakEndTime}, #{lastOrder}, #{isClosed}
)

INSERT INTO PLACE_REVIEW (
	COMMENT_NO, LOG_NO, PLACE_NO, COMMENT_CONTENT, RATING, CREATED_BY, CREATED_AT
) VALUES (
	#{commentNo}, #{logNo}, #{placeNo}, #{commentContent}, #{rating}, #{createdBy}, SYSDATE
)

mapper.update:
UPDATE PLACE_REVIEW
SET COMMENT_CONTENT = #{commentContent},
    RATING = #{rating}
WHERE COMMENT_NO = #{commentNo}
  AND PLACE_NO = #{placeNo}
  AND CREATED_BY = #{createdBy}

mapper.insert:
INSERT INTO CATEGORY (
	CATEGORY_NO, USER_NO, CATEGORY_TYPE, CATEGORY_IS_USED
) VALUES (
	#{categoryNo}, #{userNo}, #{categoryType}, #{categoryIsUsed}
)

mapper.update:
UPDATE CATEGORY
SET CATEGORY_IS_USED = #{categoryIsUsed}
WHERE CATEGORY_NO = #{categoryNo}
  AND USER_NO = #{userNo}

mapper.insert:
INSERT INTO WISHLIST (
	WISH_NO, PLACE_NO, CATEGORY_NO, USER_NO, WISH_DATE
) VALUES (
	#{wishNo}, #{placeNo}, #{categoryNo}, #{userNo}, SYSDATE
)

mapper.delete:
DELETE FROM WISHLIST
WHERE WISH_NO = #{wishNo}
  AND USER_NO = #{userNo}

DELETE FROM PHOTO_DATA
WHERE COMMENT_NO IN (
	SELECT COMMENT_NO
	FROM PLACE_REVIEW
	WHERE COMMENT_NO = #{commentNo}
	  AND PLACE_NO = #{placeNo}
	  AND CREATED_BY = #{createdBy}
)

DELETE FROM PLACE_REVIEW
WHERE COMMENT_NO = #{commentNo}
  AND PLACE_NO = #{placeNo}
  AND CREATED_BY = #{createdBy}

mapper.select:
SELECT COUNT(1)
FROM WISHLIST
WHERE USER_NO = #{userNo}
  AND PLACE_NO = #{placeNo}
  AND CATEGORY_NO = #{categoryNo}

SELECT COUNT(DISTINCT USER_NO)
FROM WISHLIST
WHERE PLACE_NO = #{placeNo}
